using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

using System.ComponentModel.DataAnnotations;

namespace TicketClassifier.Models;

public class TicketRequest
{
    [Required]
    public string Subject { get; set; } = string.Empty;

    [Required]
    public string Description { get; set; } = string.Empty;

    [Range(1, 3)]
    public int Priority { get; set; }
}

public class TicketPredictionResponse
{
    public string Category { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

public class ModelMetricsResponse
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public PerClassMetric[] PerClassMetrics { get; set; } = [];
}

public class PerClassMetric
{
    public string Class { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly ModelMetricsResponse _metrics;
    private readonly string[] _classLabels;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Combine text features and build pipeline
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(dataView);
        _predictionEngine = _mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract class labels from the trained model's key-value mapping
        var transformedData = _model.Transform(dataView);
        var labelColumn = transformedData.Schema["PredictedLabel"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        // Get labels by reading distinct values from the predicted output
        _classLabels = GetDistinctLabels(transformedData);

        // Evaluate
        var predictions = _model.Transform(dataView);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        var perClass = new List<PerClassMetric>();
        for (var i = 0; i < metrics.PerClassLogLoss.Count; i++)
        {
            perClass.Add(new PerClassMetric
            {
                Class = i < _classLabels.Length ? _classLabels[i] : $"Class {i}",
                Precision = i < metrics.PerClassLogLoss.Count ? 
                    Math.Round(1.0 - metrics.PerClassLogLoss[i], 4) : 0,
                Recall = Math.Round(1.0 - metrics.PerClassLogLoss[i], 4),
                F1Score = Math.Round(1.0 - metrics.PerClassLogLoss[i], 4)
            });
        }

        _metrics = new ModelMetricsResponse
        {
            MacroAccuracy = Math.Round(metrics.MacroAccuracy, 4),
            MicroAccuracy = Math.Round(metrics.MicroAccuracy, 4),
            LogLoss = Math.Round(metrics.LogLoss, 4),
            LogLossReduction = Math.Round(metrics.LogLossReduction, 4),
            PerClassMetrics = perClass.ToArray()
        };
    }

    private string[] GetDistinctLabels(IDataView data)
    {
        var labels = new List<string>();
        var cursor = data.GetColumn<string>("PredictedLabel");
        foreach (var label in cursor)
        {
            if (!labels.Contains(label))
                labels.Add(label);
        }
        labels.Sort();
        return labels.ToArray();
    }

    public TicketPredictionResponse Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < prediction.Score.Length && i < _classLabels.Length; i++)
        {
            confidence[_classLabels[i]] = (float)Math.Round(prediction.Score[i], 4);
        }

        return new TicketPredictionResponse
        {
            Category = prediction.Category,
            Confidence = confidence
        };
    }

    public ModelMetricsResponse GetMetrics() => _metrics;
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketsController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (!ModelState.IsValid)
            return BadRequest(ModelState);

        var result = _classifier.Predict(request);
        return Ok(result);
    }

    [HttpGet("metrics")]
    public ActionResult<ModelMetricsResponse> GetMetrics()
    {
        return Ok(_classifier.GetMetrics());
    }
}

